#[test]
fn test_parse_x11_mouse_basic() {
    let mut parser = InputParser::new();
    // X11 encoding: ESC[M followed by button+32, x+32, y+32
    // Left click at (10, 5): button=0+32=32, x=10+32=42, y=5+32=37
    let input = b"\x1b[M *%"; // 32=' ', 42='*', 37='%'
    eprintln!("[TEST] Testing X11 mouse encoding");
    eprintln!("[TEST] Input bytes: {:?}", input);

    let (event, consumed) = parser.parse(input).unwrap();
    eprintln!("[TEST] Consumed: {} bytes", consumed);

    let mouse = event.mouse().unwrap();
    eprintln!("[TEST] Mouse: ({}, {}) {:?}", mouse.x, mouse.y, mouse.button);

    // X11 coordinates are also 1-indexed, converted to 0-indexed
    assert_eq!(mouse.x, 9);
    assert_eq!(mouse.y, 4);
    assert_eq!(mouse.button, MouseButton::Left);
    eprintln!("[TEST] PASS: X11 mouse parsed correctly");
}
